import React, { useState } from "react";
import "./PathologyPage.css";

const PathologyPage = () => {
  const [selectedCheckup, setSelectedCheckup] = useState(null);

  // ✅ Full list of checkups (you can add or remove any)
  const checkups = [
    {
      title: "Full Body Checkup - Basic",
      discount: "50% Off",
      oldPrice: "₹2999",
      newPrice: "₹1499",
      parameters: 60,
      tests: "CBC, Blood Sugar, Kidney Function, Lipid Profile, Liver Function, Thyroid & more",
      reportTime: "24 hours",
    },
    {
      title: "Diabetes Checkup",
      discount: "45% Off",
      oldPrice: "₹2190",
      newPrice: "₹1199",
      parameters: 8,
      tests: "Blood Glucose (Fasting), HbA1c, Urine Sugar, Ketone Bodies & more",
      reportTime: "12 hours",
    },
    {
      title: "Thyroid Profile",
      discount: "40% Off",
      oldPrice: "₹999",
      newPrice: "₹599",
      parameters: 3,
      tests: "T3, T4, TSH",
      reportTime: "6 hours",
    },
    {
      title: "Lipid Profile",
      discount: "50% Off",
      oldPrice: "₹1099",
      newPrice: "₹549",
      parameters: 8,
      tests: "Total Cholesterol, HDL, LDL, Triglycerides & more",
      reportTime: "8 hours",
    },
    {
      title: "Liver Function Test (LFT)",
      discount: "52% Off",
      oldPrice: "₹1890",
      newPrice: "₹899",
      parameters: 11,
      tests: "Bilirubin (Total, Direct, Indirect), SGPT, SGOT, Alkaline Phosphatase & more",
      reportTime: "10 hours",
    },
    {
      title: "Kidney Function Test (KFT)",
      discount: "45% Off",
      oldPrice: "₹1799",
      newPrice: "₹999",
      parameters: 7,
      tests: "Creatinine, Urea, Uric Acid, Electrolytes & more",
      reportTime: "10 hours",
    },
    {
      title: "STD Test Checkup - Essential",
      discount: "50% Off",
      oldPrice: "₹2990",
      newPrice: "₹1499",
      parameters: 4,
      tests: "HBsAg (ECLIA), VDRL Qualitative, Hepatitis C Virus antibodies (Anti HCV) - Total & 1 other test",
      reportTime: "12 hours",
    },
    {
      title: "STD Test Checkup - Advanced",
      discount: "56% Off",
      oldPrice: "₹3190",
      newPrice: "₹1399",
      parameters: 6,
      tests: "HBsAg (ECLIA), VDRL, HCV Antibodies, HIV 1 & 2, and more",
      reportTime: "12 hours",
    },
  ];

  return (
    <div className="pathology-page">
      <h1 className="pathology-header">Popular Health Checkups</h1>

      {/* ✅ Centered card layout */}
      <div className="checkup-list">
        {checkups.map((item, index) => (
          <div
            key={index}
            className="checkup-card"
            onClick={() => setSelectedCheckup(item)}
          >
            <div className="discount-badge">{item.discount}</div>
            <h3>{item.title}</h3>
            <p className="price">
              <span className="old">{item.oldPrice}</span> {item.newPrice}
            </p>
            <button className="view-btn">View Details</button>
          </div>
        ))}
      </div>

      {/* ✅ Popup for any checkup */}
      {selectedCheckup && (
        <div className="overlay" onClick={() => setSelectedCheckup(null)}>
          <div
            className="popup"
            onClick={(e) => e.stopPropagation()}
          >
            <button className="close-btn" onClick={() => setSelectedCheckup(null)}>×</button>
            <h2>{selectedCheckup.title}</h2>
            <div className="discount-detail">{selectedCheckup.discount}</div>
            <p className="price-detail">
              <span className="old">{selectedCheckup.oldPrice}</span>{" "}
              <b>{selectedCheckup.newPrice}</b>
            </p>

            <p className="params">
              <b>{selectedCheckup.parameters} parameters included</b>
            </p>
            <p className="tests">Tests included: {selectedCheckup.tests}</p>
            <p className="report-time">
              <b>Reports within:</b> {selectedCheckup.reportTime}
            </p>

            <div className="popup-buttons">
              <button className="add-btn">+ Add</button>
              <button className="details-btn">View Details</button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default PathologyPage;
